import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  Box,
  Typography,
  Grid,
  Paper,
  Avatar,
  Button,
  Chip,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
} from "@mui/material";
import DashboardIcon from "@mui/icons-material/Dashboard";
import CalendarMonthIcon from "@mui/icons-material/CalendarMonth";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import PersonIcon from "@mui/icons-material/Person";
import LogoutIcon from "@mui/icons-material/Logout";
import CheckCircleIcon from "@mui/icons-material/CheckCircle";
import AccessTimeIcon from "@mui/icons-material/AccessTime";
import SearchIcon from "@mui/icons-material/Search";

const PRIMARY = "#1976d2";
const PRIMARY_DARK = "#1565c0";
const PRIMARY_LIGHT = "#e3f2fd";
const BG = "#f0f7ff";

const SIDEBAR_ITEMS = [
  { label: "Dashboard", value: "dashboard", icon: <DashboardIcon /> },
  {
    label: "My Appointments",
    value: "appointments",
    icon: <CalendarMonthIcon />,
  },
  { label: "Find Hospitals", value: "hospitals", icon: <LocalHospitalIcon /> },
  { label: "My Profile", value: "profile", icon: <PersonIcon /> },
];

const StatusChip = ({ status }) => {
  const config = {
    Scheduled: { color: "warning", label: "Scheduled" },
    Completed: { color: "success", label: "Completed" },
    Cancelled: { color: "error", label: "Cancelled" },
  };
  const c = config[status] || config.Scheduled;
  return (
    <Chip
      label={c.label}
      color={c.color}
      size="small"
      sx={{ fontWeight: 600 }}
    />
  );
};

export default function PatientDashboard() {
  const navigate = useNavigate();
  const [tab, setTab] = useState("dashboard");
  const [appointments, setAppointments] = useState([]);

  const patientName = localStorage.getItem("patientName") || "Patient";
  const patientEmail = localStorage.getItem("patientEmail") || "";

  useEffect(() => {
    if (localStorage.getItem("isPatientLoggedIn") !== "true") {
      navigate("/patient/login");
    }
    const saved = JSON.parse(localStorage.getItem("appointments") || "[]");
    // Filter only this patient's appointments by email or name
    setAppointments(saved);
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("isPatientLoggedIn");
    localStorage.removeItem("patientName");
    localStorage.removeItem("patientEmail");
    navigate("/");
  };

  const scheduled = appointments.filter((a) => a.status === "Scheduled").length;
  const completed = appointments.filter((a) => a.status === "Completed").length;

  return (
    <Box sx={{ display: "flex", minHeight: "100vh", bgcolor: BG }}>
      {/* ── Sidebar ── */}
      <Box
        sx={{
          width: 260,
          background: `linear-gradient(180deg, ${PRIMARY_DARK} 0%, ${PRIMARY} 100%)`,
          color: "white",
          p: 0,
          flexShrink: 0,
          display: "flex",
          flexDirection: "column",
        }}
      >
        {/* Logo */}
        <Box
          sx={{
            p: 3,
            pb: 2.5,
            borderBottom: "1px solid rgba(255,255,255,0.12)",
          }}
        >
          <Box sx={{ display: "flex", alignItems: "center", gap: 1.5 }}>
            <LocalHospitalIcon sx={{ fontSize: 28 }} />
            <Typography fontWeight={800} fontSize={18} letterSpacing="-0.5px">
              Medi<span style={{ color: "#90caf9" }}>Care</span>
            </Typography>
          </Box>
          <Chip
            label="Patient Portal"
            size="small"
            sx={{
              mt: 1,
              bgcolor: "rgba(255,255,255,0.15)",
              color: "white",
              fontSize: 11,
            }}
          />
        </Box>

        {/* Patient Info */}
        <Box
          sx={{ p: 3, pb: 2, borderBottom: "1px solid rgba(255,255,255,0.1)" }}
        >
          <Box sx={{ display: "flex", alignItems: "center", gap: 1.5 }}>
            <Avatar
              sx={{
                width: 44,
                height: 44,
                bgcolor: "rgba(255,255,255,0.2)",
                fontWeight: 700,
                fontSize: 18,
                border: "2px solid rgba(255,255,255,0.3)",
              }}
            >
              {patientName.charAt(0).toUpperCase()}
            </Avatar>
            <Box>
              <Typography fontWeight={700} fontSize={14}>
                {patientName}
              </Typography>
              <Typography
                fontSize={12}
                sx={{ color: "rgba(255,255,255,0.65)" }}
              >
                {patientEmail}
              </Typography>
            </Box>
          </Box>
        </Box>

        {/* Nav */}
        <List sx={{ pt: 1.5, flex: 1 }}>
          {SIDEBAR_ITEMS.map(({ label, value, icon }) => (
            <ListItem
              key={value}
              onClick={() =>
                value === "hospitals" ? navigate("/") : setTab(value)
              }
              sx={{
                mx: 1.5,
                mb: 0.5,
                borderRadius: 2,
                cursor: "pointer",
                bgcolor:
                  tab === value ? "rgba(255,255,255,0.18)" : "transparent",
                borderLeft:
                  tab === value ? "3px solid #90caf9" : "3px solid transparent",
                "&:hover": { bgcolor: "rgba(255,255,255,0.1)" },
                transition: "all 0.2s",
              }}
            >
              <ListItemIcon
                sx={{
                  color: tab === value ? "white" : "rgba(255,255,255,0.6)",
                  minWidth: 36,
                }}
              >
                {icon}
              </ListItemIcon>
              <ListItemText
                primary={label}
                primaryTypographyProps={{
                  fontSize: 14,
                  fontWeight: tab === value ? 700 : 400,
                  color: tab === value ? "white" : "rgba(255,255,255,0.7)",
                }}
              />
            </ListItem>
          ))}
        </List>

        <Divider sx={{ bgcolor: "rgba(255,255,255,0.12)", mx: 2 }} />
        <List sx={{ pb: 2 }}>
          <ListItem
            onClick={handleLogout}
            sx={{
              mx: 1.5,
              borderRadius: 2,
              cursor: "pointer",
              "&:hover": { bgcolor: "rgba(255,255,255,0.1)" },
            }}
          >
            <ListItemIcon sx={{ color: "rgba(255,255,255,0.6)", minWidth: 36 }}>
              <LogoutIcon />
            </ListItemIcon>
            <ListItemText
              primary="Logout"
              primaryTypographyProps={{
                fontSize: 14,
                color: "rgba(255,255,255,0.7)",
              }}
            />
          </ListItem>
        </List>
      </Box>

      {/* ── Main Content ── */}
      <Box sx={{ flex: 1, p: 4, overflow: "auto" }}>
        {/* Top bar */}
        <Box
          sx={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            mb: 4,
          }}
        >
          <Box>
            <Typography
              variant="h5"
              fontWeight={800}
              color="#0d2a2a"
              letterSpacing="-0.5px"
            >
              {tab === "dashboard" && `Welcome back, ${patientName} 👋`}
              {tab === "appointments" && "My Appointments"}
              {tab === "profile" && "My Profile"}
            </Typography>
            <Typography variant="body2" color="text.secondary" mt={0.5}>
              {new Date().toLocaleDateString("en-US", {
                weekday: "long",
                year: "numeric",
                month: "long",
                day: "numeric",
              })}
            </Typography>
          </Box>
          <Button
            variant="contained"
            startIcon={<SearchIcon />}
            onClick={() => navigate("/")}
            sx={{
              borderRadius: 3,
              fontWeight: 600,
              background: `linear-gradient(90deg, ${PRIMARY_DARK}, ${PRIMARY})`,
              boxShadow: "0 4px 12px rgba(25,118,210,0.25)",
            }}
          >
            Find Hospital
          </Button>
        </Box>

        {/* ── DASHBOARD TAB ── */}
        {tab === "dashboard" && (
          <>
            {/* Stat Cards */}
            <Grid container spacing={3} sx={{ mb: 4 }}>
              {[
                {
                  label: "Total Appointments",
                  value: appointments.length,
                  icon: "📅",
                  color: PRIMARY,
                },
                {
                  label: "Upcoming",
                  value: scheduled,
                  icon: "⏰",
                  color: "#ed6c02",
                },
                {
                  label: "Completed",
                  value: completed,
                  icon: "✅",
                  color: "#2e7d32",
                },
              ].map((s) => (
                <Grid item xs={12} sm={4} key={s.label}>
                  <Paper
                    elevation={0}
                    sx={{
                      p: 3,
                      borderRadius: 3,
                      border: "1px solid rgba(25,118,210,0.1)",
                      boxShadow: "0 2px 16px rgba(25,118,210,0.06)",
                      display: "flex",
                      alignItems: "center",
                      gap: 2,
                    }}
                  >
                    <Box
                      sx={{
                        width: 54,
                        height: 54,
                        borderRadius: 2,
                        bgcolor: `${s.color}15`,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        fontSize: 26,
                      }}
                    >
                      {s.icon}
                    </Box>
                    <Box>
                      <Typography variant="h4" fontWeight={800} color="#0d2a2a">
                        {s.value}
                      </Typography>
                      <Typography
                        variant="body2"
                        color="text.secondary"
                        fontWeight={500}
                      >
                        {s.label}
                      </Typography>
                    </Box>
                  </Paper>
                </Grid>
              ))}
            </Grid>

            {/* Recent Appointments */}
            <Paper
              elevation={0}
              sx={{
                p: 3,
                borderRadius: 3,
                border: "1px solid rgba(25,118,210,0.1)",
                boxShadow: "0 2px 16px rgba(25,118,210,0.06)",
                mb: 3,
              }}
            >
              <Box
                sx={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                  mb: 2.5,
                }}
              >
                <Typography variant="h6" fontWeight={700} color="#0d2a2a">
                  Recent Appointments
                </Typography>
                <Button
                  size="small"
                  onClick={() => setTab("appointments")}
                  sx={{ color: PRIMARY, fontWeight: 600 }}
                >
                  View All →
                </Button>
              </Box>

              {appointments.length === 0 ? (
                <Box sx={{ textAlign: "center", py: 5 }}>
                  <Typography fontSize={48}>🗓️</Typography>
                  <Typography color="text.secondary" mt={1}>
                    No appointments yet
                  </Typography>
                  <Button
                    variant="contained"
                    onClick={() => navigate("/")}
                    sx={{
                      mt: 2,
                      borderRadius: 3,
                      background: `linear-gradient(90deg, ${PRIMARY_DARK}, ${PRIMARY})`,
                    }}
                  >
                    Book Now
                  </Button>
                </Box>
              ) : (
                <TableContainer>
                  <Table>
                    <TableHead>
                      <TableRow>
                        {["Doctor", "Hospital", "Date", "Time", "Status"].map(
                          (h) => (
                            <TableCell
                              key={h}
                              sx={{
                                fontWeight: 700,
                                color: "text.secondary",
                                fontSize: 12,
                                textTransform: "uppercase",
                              }}
                            >
                              {h}
                            </TableCell>
                          ),
                        )}
                      </TableRow>
                    </TableHead>
                    <TableBody>
                      {appointments.slice(0, 5).map((a) => (
                        <TableRow key={a.id} hover>
                          <TableCell sx={{ fontWeight: 600 }}>
                            {a.doctorName || "—"}
                          </TableCell>
                          <TableCell>{a.hospitalName || "—"}</TableCell>
                          <TableCell>{a.date || "—"}</TableCell>
                          <TableCell>{a.preferredTime || "—"}</TableCell>
                          <TableCell>
                            <StatusChip status={a.status} />
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </TableContainer>
              )}
            </Paper>

            {/* Quick Actions */}
            <Paper
              elevation={0}
              sx={{
                p: 3,
                borderRadius: 3,
                border: "1px solid rgba(25,118,210,0.1)",
                boxShadow: "0 2px 16px rgba(25,118,210,0.06)",
              }}
            >
              <Typography variant="h6" fontWeight={700} color="#0d2a2a" mb={2}>
                Quick Actions
              </Typography>
              <Grid container spacing={2}>
                {[
                  {
                    icon: "🏥",
                    label: "Find Hospital",
                    sub: "Search & browse",
                    action: () => navigate("/"),
                  },
                  {
                    icon: "📅",
                    label: "My Bookings",
                    sub: "View appointments",
                    action: () => setTab("appointments"),
                  },
                  {
                    icon: "👤",
                    label: "My Profile",
                    sub: "Account details",
                    action: () => setTab("profile"),
                  },
                  {
                    icon: "💊",
                    label: "Specialties",
                    sub: "Browse by specialty",
                    action: () => navigate("/"),
                  },
                ].map((item) => (
                  <Grid item xs={6} sm={3} key={item.label}>
                    <Box
                      onClick={item.action}
                      sx={{
                        p: 2.5,
                        borderRadius: 3,
                        cursor: "pointer",
                        bgcolor: PRIMARY_LIGHT,
                        border: `1px solid rgba(25,118,210,0.15)`,
                        textAlign: "center",
                        transition: "all 0.2s",
                        "&:hover": {
                          transform: "translateY(-2px)",
                          boxShadow: "0 4px 16px rgba(25,118,210,0.15)",
                        },
                      }}
                    >
                      <Typography fontSize={28}>{item.icon}</Typography>
                      <Typography
                        fontWeight={700}
                        fontSize={13}
                        color={PRIMARY}
                        mt={1}
                      >
                        {item.label}
                      </Typography>
                      <Typography fontSize={11} color="text.secondary">
                        {item.sub}
                      </Typography>
                    </Box>
                  </Grid>
                ))}
              </Grid>
            </Paper>
          </>
        )}

        {/* ── APPOINTMENTS TAB ── */}
        {tab === "appointments" && (
          <Paper
            elevation={0}
            sx={{
              p: 3,
              borderRadius: 3,
              border: "1px solid rgba(25,118,210,0.1)",
              boxShadow: "0 2px 16px rgba(25,118,210,0.06)",
            }}
          >
            <Typography variant="h6" fontWeight={700} color="#0d2a2a" mb={3}>
              All Appointments ({appointments.length})
            </Typography>
            {appointments.length === 0 ? (
              <Box sx={{ textAlign: "center", py: 8 }}>
                <Typography fontSize={56}>📭</Typography>
                <Typography color="text.secondary" mt={1} mb={2}>
                  No appointments found
                </Typography>
                <Button
                  variant="contained"
                  onClick={() => navigate("/")}
                  sx={{
                    borderRadius: 3,
                    background: `linear-gradient(90deg, ${PRIMARY_DARK}, ${PRIMARY})`,
                  }}
                >
                  Book an Appointment
                </Button>
              </Box>
            ) : (
              <TableContainer>
                <Table>
                  <TableHead>
                    <TableRow>
                      {[
                        "Patient",
                        "Doctor",
                        "Hospital",
                        "Date",
                        "Time",
                        "Payment",
                        "Amount",
                        "Status",
                      ].map((h) => (
                        <TableCell
                          key={h}
                          sx={{
                            fontWeight: 700,
                            color: "text.secondary",
                            fontSize: 12,
                            textTransform: "uppercase",
                          }}
                        >
                          {h}
                        </TableCell>
                      ))}
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {appointments.map((a) => (
                      <TableRow key={a.id} hover>
                        <TableCell sx={{ fontWeight: 600 }}>
                          {a.patientName || "—"}
                        </TableCell>
                        <TableCell>{a.doctorName || "—"}</TableCell>
                        <TableCell>{a.hospitalName || "—"}</TableCell>
                        <TableCell>{a.date || "—"}</TableCell>
                        <TableCell>{a.preferredTime || "—"}</TableCell>
                        <TableCell>{a.paymentMethod || "—"}</TableCell>
                        <TableCell>NPR {a.amount || 500}</TableCell>
                        <TableCell>
                          <StatusChip status={a.status} />
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>
            )}
          </Paper>
        )}

        {/* ── PROFILE TAB ── */}
        {tab === "profile" && (
          <Paper
            elevation={0}
            sx={{
              p: 4,
              borderRadius: 3,
              border: "1px solid rgba(25,118,210,0.1)",
              boxShadow: "0 2px 16px rgba(25,118,210,0.06)",
            }}
          >
            <Typography variant="h6" fontWeight={700} color="#0d2a2a" mb={3}>
              My Profile
            </Typography>
            <Box sx={{ display: "flex", alignItems: "center", gap: 3, mb: 4 }}>
              <Avatar
                sx={{
                  width: 80,
                  height: 80,
                  background: `linear-gradient(135deg, ${PRIMARY_DARK}, ${PRIMARY})`,
                  fontSize: 32,
                  fontWeight: 700,
                }}
              >
                {patientName.charAt(0).toUpperCase()}
              </Avatar>
              <Box>
                <Typography variant="h5" fontWeight={800} color="#0d2a2a">
                  {patientName}
                </Typography>
                <Typography color="text.secondary">{patientEmail}</Typography>
                <Chip
                  label="Patient"
                  size="small"
                  sx={{
                    mt: 1,
                    bgcolor: PRIMARY_LIGHT,
                    color: PRIMARY,
                    fontWeight: 600,
                  }}
                />
              </Box>
            </Box>

            <Grid container spacing={2}>
              {[
                {
                  label: "Total Appointments",
                  value: appointments.length,
                  icon: "📅",
                },
                { label: "Upcoming", value: scheduled, icon: "⏰" },
                { label: "Completed", value: completed, icon: "✅" },
                { label: "Member Since", value: "2024", icon: "🗓️" },
              ].map((item) => (
                <Grid item xs={6} sm={3} key={item.label}>
                  <Box
                    sx={{
                      p: 2.5,
                      borderRadius: 3,
                      bgcolor: PRIMARY_LIGHT,
                      textAlign: "center",
                    }}
                  >
                    <Typography fontSize={24}>{item.icon}</Typography>
                    <Typography
                      variant="h5"
                      fontWeight={800}
                      color={PRIMARY}
                      mt={1}
                    >
                      {item.value}
                    </Typography>
                    <Typography fontSize={12} color="text.secondary" mt={0.5}>
                      {item.label}
                    </Typography>
                  </Box>
                </Grid>
              ))}
            </Grid>

            <Button
              variant="outlined"
              color="error"
              startIcon={<LogoutIcon />}
              onClick={handleLogout}
              sx={{ mt: 4, borderRadius: 3 }}
            >
              Logout
            </Button>
          </Paper>
        )}
      </Box>
    </Box>
  );
}
